document.addEventListener("DOMContentLoaded", function () {
    var toggles = document.querySelectorAll("[data-bs-toggle='collapse']");

    toggles.forEach(function (toggle) {
        toggle.addEventListener("click", function () {
            var targetSelector = toggle.getAttribute("data-bs-target");
            var target = document.querySelector(targetSelector);

            if (!target) {
                return;
            }

            var isOpen = target.classList.contains("show");
            target.classList.toggle("show", !isOpen);
            toggle.setAttribute("aria-expanded", String(!isOpen));
        });
    });

    // Dropdown Logic
    var dropdownToggles = document.querySelectorAll("[data-bs-toggle='dropdown']");
    dropdownToggles.forEach(function (toggle) {
        toggle.addEventListener("click", function (e) {
            e.preventDefault();
            e.stopPropagation();
            var menu = toggle.nextElementSibling;
            if (menu && menu.classList.contains("dropdown-menu")) {
                var isOpen = menu.classList.contains("show");
                // Close all other dropdowns
                document.querySelectorAll(".dropdown-menu.show").forEach(function(m) {
                    if (m !== menu) {
                        m.classList.remove("show");
                        if (m.previousElementSibling) m.previousElementSibling.setAttribute("aria-expanded", "false");
                    }
                });
                menu.classList.toggle("show", !isOpen);
                toggle.setAttribute("aria-expanded", String(!isOpen));
            }
        });
    });

    // Close dropdowns when clicking outside
    document.addEventListener("click", function (e) {
        document.querySelectorAll(".dropdown-menu.show").forEach(function (menu) {
            if (!menu.contains(e.target)) {
                menu.classList.remove("show");
                if (menu.previousElementSibling) menu.previousElementSibling.setAttribute("aria-expanded", "false");
            }
        });
    });

    // Modal Logic
    var modalToggles = document.querySelectorAll("[data-bs-toggle='modal']");
    modalToggles.forEach(function (toggle) {
        toggle.addEventListener("click", function () {
            var targetId = toggle.getAttribute("data-bs-target");
            var modal = document.querySelector(targetId);
            if (modal) {
                modal.classList.add("show");
            }
        });
    });

    var modalCloseButtons = document.querySelectorAll("[data-bs-dismiss='modal']");
    modalCloseButtons.forEach(function (btn) {
        btn.addEventListener("click", function () {
            var modal = btn.closest(".modal");
            if (modal) {
                modal.classList.remove("show");
            }
        });
    });
});
